document.addEventListener('DOMContentLoaded',()=>{document.addEventListener('click',e=>{const toggle=e.target.closest('.nav-toggle');const menu=document.querySelector('.nav-menu');if(!toggle||!menu)return;const open=menu.classList.toggle('open');toggle.classList.toggle('open',open);toggle.setAttribute('aria-expanded',open);document.body.style.overflow=open?'hidden':'';});document.addEventListener('click',e=>{const menu=document.querySelector('.nav-menu');const toggle=document.querySelector('.nav-toggle');if(!menu?.classList.contains('open'))return;if(!menu.contains(e.target)&&!toggle.contains(e.target)){menu.classList.remove('open');toggle.classList.remove('open');toggle.setAttribute('aria-expanded','false');document.body.style.overflow='';}});window.addEventListener('resize',()=>{if(window.innerWidth>768){const menu=document.querySelector('.nav-menu');const toggle=document.querySelector('.nav-toggle');menu?.classList.remove('open');toggle?.classList.remove('open');document.body.style.overflow='';}});document.querySelectorAll('.faq-question').forEach(btn=>{btn.addEventListener('click',()=>{const isOpen=btn.classList.contains('open');document.querySelectorAll('.faq-question').forEach(q=>{q.classList.remove('open');q.setAttribute('aria-expanded','false');q.nextElementSibling?.classList.remove('open');});if(!isOpen){btn.classList.add('open');btn.setAttribute('aria-expanded','true');btn.nextElementSibling?.classList.add('open');}});btn.addEventListener('keydown',e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();btn.click();}});});if('IntersectionObserver'in window){const observer=new IntersectionObserver((entries)=>{entries.forEach(el=>{if(el.isIntersecting){el.target.classList.add('visible');observer.unobserve(el.target);}});},{threshold:0.12,rootMargin:'0px 0px -40px 0px'});document.querySelectorAll('.reveal').forEach(el=>observer.observe(el));}else{document.querySelectorAll('.reveal').forEach(el=>el.classList.add('visible'));}
const header=document.querySelector('.site-header');if(header){window.addEventListener('scroll',()=>{header.style.boxShadow=window.scrollY>20?'0 4px 24px rgba(0,0,0,0.10)':'0 2px 12px rgba(0,0,0,0.05)';},{passive:true});}
const form=document.getElementById('contact-form');if(form){form.addEventListener('submit',async e=>{e.preventDefault();const btn=form.querySelector('button[type="submit"]');const success=document.getElementById('form-success');const original=btn.textContent;btn.textContent='Sending…';btn.disabled=true;try{const res=await fetch(form.action,{method:'POST',body:new FormData(form),headers:{'Accept':'application/json'}});if(res.ok){form.reset();if(success)success.style.display='block';btn.textContent='Sent!';setTimeout(()=>{btn.textContent=original;btn.disabled=false;if(success)success.style.display='none';},5000);}else{throw new Error('Server error');}}catch{btn.textContent='Error — try again';btn.disabled=false;setTimeout(()=>{btn.textContent=original;},3000);}});}
document.querySelectorAll('.newsletter-form').forEach(nf=>{nf.addEventListener('submit',e=>{e.preventDefault();const btn=nf.querySelector('button');btn.textContent='✓ Subscribed!';btn.disabled=true;setTimeout(()=>{btn.textContent='Subscribe';btn.disabled=false;nf.reset();},3000);});});});